<template><div class="composer"><div class="shortcuts"><button v-for="x in ['相册','小额打款','物流客服','邀请下单']" @click="$emit('action',x)">{{x}}</button></div><form @submit.prevent="send"><button type="button" @click="panel=!panel"><MessageSquare/></button><textarea ref="input" v-model="text" placeholder="输入消息" rows="1" @keydown.enter.exact.prevent="send"/><button type="button" @click="emoji=!emoji"><Smile/></button><button type="button" :disabled="uploading" @click="file?.click()"><Plus/></button><input ref="file" hidden type="file" accept="image/*,video/mp4,video/webm,video/quicktime" @change="upload"><button v-if="text.trim()" class="send">发送</button></form><div v-if="emoji" class="shortcuts"><button v-for="e in emojis" @click="insert(e)">{{e}}</button></div><div v-if="panel" style="padding:12px;background:white"><input v-model="keyword" placeholder="搜索快捷短语" @input="load"><button @click="edit()">新增短语</button><div v-for="q in replies" :key="q.id"><button @click="insert(q.content)">{{q.content}}</button><button @click="edit(q)">编辑</button><button @click="remove(q.id)">删除</button></div></div></div></template>
<script setup lang="ts">import{ref,onMounted}from'vue';import{MessageSquare,Smile,Plus}from'lucide-vue-next';const emit=defineEmits(['send','upload','action']);const text=ref(''),input=ref<HTMLTextAreaElement>(),file=ref<HTMLInputElement>(),emoji=ref(false),panel=ref(false),uploading=ref(false),keyword=ref(''),replies=ref<any[]>([]),emojis=['😀','😃','😄','😁','😆','😂','😊','😍','😘','😎','😭','😡','👍','👎','🙏','🎉','❤️'];function send(){if(!text.value.trim())return;emit('send',text.value.trim());text.value=''}function insert(v:string){const el=input.value,p=el?.selectionStart??text.value.length;text.value=text.value.slice(0,p)+v+text.value.slice(p);setTimeout(()=>{el?.focus();el?.setSelectionRange(p+v.length,p+v.length)})}async function load(){const r=await fetch('/api/koshop-seller/quick-replies?keyword='+encodeURIComponent(keyword.value));replies.value=(await r.json()).items||[]}async function edit(q?:any){const content=prompt(q?'修改短语':'新增短语',q?.content||'')?.trim();if(!content)return;await fetch('/api/koshop-seller/quick-replies'+(q?'/'+q.id:''),{method:q?'PUT':'POST',headers:{'content-type':'application/json'},body:JSON.stringify({content})});load()}async function remove(id:string){if(!confirm('确定删除这条快捷短语吗？'))return;await fetch('/api/koshop-seller/quick-replies/'+id,{method:'DELETE'});load()}async function upload(e:Event){const f=(e.target as HTMLInputElement).files?.[0];if(!f)return;uploading.value=true;emit('upload',f,()=>uploading.value=false);(e.target as HTMLInputElement).value=''}onMounted(load)</script>
